import { openai } from '@ai-sdk/openai';
import { generateObject, object } from 'ai';
import { vexVerify } from 'vex-sdk';

const candidateSchema = object({
  name: 'string',
  experience: object({
    years: 'number',
    roles: array('string'),
    gaps: array('string') // Flag employment gaps
  }),
  skills: array('string'),
  aiUsed: 'boolean',
  accommodations: array('string').optional()
});

const parseResume = vexVerify(async (resume: string) => {
  const { object } = await generateObject({
    model: openai('gpt-4o'),
    schema: candidateSchema,
    prompt: `Parse this resume for structured hiring data: ${resume}`
  });
  return object;
});
